// ============= FIXTURES =============
// 180 SaaS accounts from a seeded mulberry32 PRNG evaluated once at module
// load — pure, replayable, and identical on every render and every machine.

type SegmentId = 'enterprise' | 'midmarket' | 'smb' | 'startup';
type RegionId = 'na' | 'emea' | 'apac' | 'latam';

interface Account {
  id: string;
  name: string;
  segment: SegmentId;
  region: RegionId;
  /** Monthly spend in dollars, 0–10,000. */
  spend: number;
  /** Weekly active engagement, 0–100%. */
  engagement: number;
  /** Provisioned seats. */
  seats: number;
}

const SEGMENTS: ReadonlyArray<{
  id: SegmentId;
  label: string;
  color: string;
}> = [
  {id: 'enterprise', label: 'Enterprise', color: colors.enterprise},
  {id: 'midmarket', label: 'Mid-market', color: colors.midmarket},
  {id: 'smb', label: 'SMB', color: colors.smb},
  {id: 'startup', label: 'Startup', color: colors.startup},
];

const SEGMENT_LABEL: Record<SegmentId, string> = {
  enterprise: 'Enterprise',
  midmarket: 'Mid-market',
  smb: 'SMB',
  startup: 'Startup',
};

const SEGMENT_COLOR: Record<SegmentId, string> = {
  enterprise: colors.enterprise,
  midmarket: colors.midmarket,
  smb: colors.smb,
  startup: colors.startup,
};

const REGION_LABEL: Record<RegionId, string> = {
  na: 'North America',
  emea: 'EMEA',
  apac: 'APAC',
  latam: 'LATAM',
};

const REGION_IDS: ReadonlyArray<RegionId> = ['na', 'emea', 'apac', 'latam'];

// 20 x 9 name parts = exactly 180 unique account names.
const NAME_HEADS = [
  'Alder', 'Basalt', 'Cinder', 'Dovetail', 'Emberline', 'Foxglove', 'Granite',
  'Harborlight', 'Ironwood', 'Juniper', 'Kestrel', 'Larkspur', 'Meridian',
  'Northbeam', 'Opaline', 'Pinewood', 'Quarry', 'Riverbend', 'Saltgrass',
  'Timberline',
] as const;
const NAME_TAILS = [
  'Labs', 'Systems', 'Logistics', 'Analytics', 'Health', 'Robotics',
  'Financial', 'Media', 'Manufacturing',
] as const;

/** Standard mulberry32: deterministic 32-bit PRNG, fixed seed. */
function mulberry32(seed: number): () => number {
  let a = seed >>> 0;
  return () => {
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

/** Per-segment envelopes keep spend/engagement/seats plausibly clustered. */
const SEGMENT_ENVELOPE: Record<
  SegmentId,
  {
    spend: [number, number];
    engagement: [number, number];
    seats: [number, number];
  }
> = {
  enterprise: {spend: [4200, 9800], engagement: [38, 92], seats: [120, 420]},
  midmarket: {spend: [2200, 6400], engagement: [30, 88], seats: [40, 170]},
  smb: {spend: [700, 3300], engagement: [18, 82], seats: [8, 64]},
  startup: {spend: [200, 1700], engagement: [10, 96], seats: [3, 26]},
};

// Segment mix: 0.2 enterprise / 0.3 mid-market / 0.3 SMB / 0.2 startup.
function segmentFor(roll: number): SegmentId {
  if (roll < 0.2) {
    return 'enterprise';
  }
  if (roll < 0.5) {
    return 'midmarket';
  }
  if (roll < 0.8) {
    return 'smb';
  }
  return 'startup';
}

function buildAccounts(): Account[] {
  const rand = mulberry32(20260703);
  const accounts: Account[] = [];
  for (let i = 0; i < 180; i++) {
    const segment = segmentFor(rand());
    const env = SEGMENT_ENVELOPE[segment];
    const spendT = rand();
    const spend =
      Math.round((env.spend[0] + (env.spend[1] - env.spend[0]) * spendT) / 10) *
      10;
    // Engagement is loosely correlated with spend (0.55 weight) plus noise,
    // clamped to the segment envelope so clusters stay readable.
    const engT = Math.min(1, Math.max(0, spendT * 0.55 + rand() * 0.45));
    const engagement = Math.round(
      env.engagement[0] + (env.engagement[1] - env.engagement[0]) * engT,
    );
    const seatT = Math.min(1, Math.max(0, spendT * 0.7 + rand() * 0.3));
    const seats = Math.round(
      env.seats[0] + (env.seats[1] - env.seats[0]) * seatT,
    );
    accounts.push({
      id: `acct-${String(i + 1).padStart(3, '0')}`,
      name: `${NAME_HEADS[i % NAME_HEADS.length]} ${
        NAME_TAILS[Math.floor(i / NAME_HEADS.length) % NAME_TAILS.length]
      }`,
      segment,
      region: REGION_IDS[Math.floor(rand() * REGION_IDS.length)],
      spend,
      engagement,
      seats,
    });
  }
  return accounts;
}

const ACCOUNTS: ReadonlyArray<Account> = buildAccounts();
const TOTAL_SEATS = ACCOUNTS.reduce((sum, a) => sum + a.seats, 0);

// ============= SCALES & FORMATTERS (hand-rolled, deterministic) =============

const SPEND_MAX = 10000;
const ENG_MAX = 100;
const SEATS_MAX = 420;

/** Evenly spaced axis ticks including both endpoints. */
function tickValues(max: number, step: number): number[] {
  const ticks: number[] = [];
  for (let v = 0; v <= max; v += step) {
    ticks.push(v);
  }
  return ticks;
}

const SPEND_TICKS = tickValues(SPEND_MAX, 2000);
const ENG_TICKS = tickValues(ENG_MAX, 20);

function formatMoney(value: number): string {
  return value >= 1000
    ? `$${(value / 1000).toFixed(value % 1000 === 0 ? 0 : 1)}k`
    : `$${Math.round(value)}`;
}

function formatCount(value: number): string {
  return value.toLocaleString('en-US');
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(max, Math.max(min, value));
}

function median(values: number[]): number {
  if (values.length === 0) {
    return 0;
  }
  const sorted = [...values].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 === 1
    ? sorted[mid]
    : (sorted[mid - 1] + sorted[mid]) / 2;
}

// ============= SHARED SELECTION REDUCER =============
// One reducer owns every linked selection: the scatter's rectangle brush
// (data units), the histogram's spend range (snapped to bin edges), and the
// segment toggles. Pointer gestures, corner handles, keyboard nudges, bin
// clicks, and preset buttons all dispatch the same actions — direct
// manipulation IS the filter mechanism; no control panel mediates the data.

interface BrushRect {
  /** Ordered spend bounds in dollars, spend0 <= spend1. */
  spend0: number;
  spend1: number;
  /** Ordered engagement bounds in percent, eng0 <= eng1. */
  eng0: number;
  eng1: number;
}

interface SpendRange {
  min: number;
  max: number;
}

interface Selection {
  scatter: BrushRect | null;
  spend: SpendRange | null;
  segments: ReadonlyArray<SegmentId>;
}

type SelectionAction =
  | {type: 'scatter-brush'; rect: BrushRect}
  | {type: 'clear-scatter'}
  | {type: 'spend-range'; range: SpendRange}
  | {type: 'clear-spend'}
  | {type: 'toggle-segment'; segment: SegmentId}
  | {type: 'clear-all'};

const EMPTY_SELECTION: Selection = {scatter: null, spend: null, segments: []};

function selectionReducer(state: Selection, action: SelectionAction): Selection {
  switch (action.type) {
    case 'scatter-brush':
      return {...state, scatter: action.rect};
    case 'clear-scatter':
      return {...state, scatter: null};
    case 'spend-range':
      return {...state, spend: action.range};
    case 'clear-spend':
      return {...state, spend: null};
    case 'toggle-segment': {
      const has = state.segments.includes(action.segment);
      return {
        ...state,
        segments: has
          ? state.segments.filter(s => s !== action.segment)
          : [...state.segments, action.segment],
      };
    }
    case 'clear-all':
      return EMPTY_SELECTION;
  }
}

type Facet = 'scatter' | 'spend' | 'segments';

/**
 * Cross-filter predicate. `ignore` implements the linking convention: each
 * chart draws its base data filtered by every facet except its own, so the
 * histogram reacts to the scatter brush and vice versa without feedback.
 */
function accountPasses(
  account: Account,
  selection: Selection,
  ignore?: Facet,
): boolean {
  if (ignore !== 'scatter' && selection.scatter != null) {
    const b = selection.scatter;
    if (
      account.spend < b.spend0 ||
      account.spend > b.spend1 ||
      account.engagement < b.eng0 ||
      account.engagement > b.eng1
    ) {
      return false;
    }
  }
  if (ignore !== 'spend' && selection.spend != null) {
    if (
      account.spend < selection.spend.min ||
      account.spend > selection.spend.max
    ) {
      return false;
    }
  }
  if (ignore !== 'segments' && selection.segments.length > 0) {
    if (!selection.segments.includes(account.segment)) {
      return false;
    }
  }
  return true;
}

// Preset brushes — the button path that drives the exact same commit logic
// as the drag gesture (and doubles as a one-tap entry point on touch).
