// ============= SCATTER (hand-rolled SVG + rectangle brush) =============

const VB_W = 640;
const VB_H = 400;
const PAD = {top: 14, right: 14, bottom: 34, left: 50};
const PLOT_W = VB_W - PAD.left - PAD.right;
const PLOT_H = VB_H - PAD.top - PAD.bottom;

/** Data → viewBox px. Pure and deterministic: same fixtures, same pixels. */
function xOf(spend: number): number {
  return PAD.left + (spend / SPEND_MAX) * PLOT_W;
}
function yOf(engagement: number): number {
  return PAD.top + (1 - engagement / ENG_MAX) * PLOT_H;
}
/** ViewBox px → data, clamped to the plot domain. */
function spendAt(px: number): number {
  return clamp(((px - PAD.left) / PLOT_W) * SPEND_MAX, 0, SPEND_MAX);
}
function engAt(py: number): number {
  return clamp((1 - (py - PAD.top) / PLOT_H) * ENG_MAX, 0, ENG_MAX);
}
/** Dot radius from seats: sqrt scale so area tracks the value. */
function dotRadius(seats: number): number {
  return 3 + Math.sqrt(seats / SEATS_MAX) * 9;
}

type HandleId = 'nw' | 'ne' | 'sw' | 'se';

interface HandlePoint {
  id: HandleId;
  x: number;
  y: number;
}

function brushHandles(rect: BrushRect): HandlePoint[] {
  const x0 = xOf(rect.spend0);
  const x1 = xOf(rect.spend1);
  const yTop = yOf(rect.eng1);
  const yBottom = yOf(rect.eng0);
  return [
    {id: 'nw', x: x0, y: yTop},
    {id: 'ne', x: x1, y: yTop},
    {id: 'sw', x: x0, y: yBottom},
    {id: 'se', x: x1, y: yBottom},
  ];
}

function orderedRect(
  spendA: number,
  spendB: number,
  engA: number,
  engB: number,
): BrushRect {
  return {
    spend0: Math.min(spendA, spendB),
    spend1: Math.max(spendA, spendB),
    eng0: Math.min(engA, engB),
    eng1: Math.max(engA, engB),
  };
}

interface ScatterGesture {
  mode: 'draw' | 'move' | 'resize';
  pointerId: number;
  /** Anchor (draw) or grab point (move) in data units. */
  spend: number;
  eng: number;
  orig: BrushRect | null;
  handle: HandleId | null;
  moved: boolean;
}

const KEY_STEP_SPEND = SPEND_MAX * 0.05;
const KEY_STEP_ENG = ENG_MAX * 0.05;
const MIN_BRUSH_SPEND = SPEND_MAX * 0.04;
const MIN_BRUSH_ENG = ENG_MAX * 0.04;

function ScatterBrushChart({
  selection,
  selectedIds,
  dispatch,
  isTouch,
  reducedMotion,
}: {
  selection: Selection;
  selectedIds: ReadonlySet<string>;
  dispatch: Dispatch<SelectionAction>;
  isTouch: boolean;
  reducedMotion: boolean;
}) {
  const svgRef = useRef<SVGSVGElement | null>(null);
  const gestureRef = useRef<ScatterGesture | null>(null);
  const [isFocused, setIsFocused] = useState(false);
  const brush = selection.scatter;
  // Touch pointers get ~44px corner hit zones (viewBox units track CSS px
  // closely at typical card widths); mouse pointers get tighter 9px zones.
  const handleHit = isTouch ? 22 : 9;

  const toViewBox = (event: ReactPointerEvent<SVGSVGElement>) => {
    const node = svgRef.current;
    if (node == null) {
      return {x: 0, y: 0};
    }
    const bounds = node.getBoundingClientRect();
    return {
      x: ((event.clientX - bounds.left) / bounds.width) * VB_W,
      y: ((event.clientY - bounds.top) / bounds.height) * VB_H,
    };
  };

  const handlePointerDown = (event: ReactPointerEvent<SVGSVGElement>) => {
    if (event.pointerType === 'mouse' && event.button !== 0) {
      return;
    }
    const point = toViewBox(event);
    const spend = spendAt(point.x);
    const eng = engAt(point.y);
    let gesture: ScatterGesture = {
      mode: 'draw',
      pointerId: event.pointerId,
      spend,
      eng,
      orig: null,
      handle: null,
      moved: false,
    };
    if (brush != null) {
      // Hit-test corner handles first, then the brush body.
      const grabbed = brushHandles(brush).find(
        handle =>
          Math.abs(point.x - handle.x) <= handleHit &&
          Math.abs(point.y - handle.y) <= handleHit,
      );
      if (grabbed != null) {
        gesture = {...gesture, mode: 'resize', orig: brush, handle: grabbed.id};
      } else if (
        spend >= brush.spend0 &&
        spend <= brush.spend1 &&
        eng >= brush.eng0 &&
        eng <= brush.eng1
      ) {
        gesture = {...gesture, mode: 'move', orig: brush};
      }
    }
    gestureRef.current = gesture;
    event.currentTarget.setPointerCapture(event.pointerId);
    event.preventDefault();
  };

  const handlePointerMove = (event: ReactPointerEvent<SVGSVGElement>) => {
    const gesture = gestureRef.current;
    if (gesture == null || gesture.pointerId !== event.pointerId) {
      return;
    }
    const point = toViewBox(event);
    const spend = spendAt(point.x);
    const eng = engAt(point.y);
    gesture.moved = true;
    if (gesture.mode === 'draw') {
      dispatch({
        type: 'scatter-brush',
        rect: orderedRect(gesture.spend, spend, gesture.eng, eng),
      });
      return;
    }
    const orig = gesture.orig;
    if (orig == null) {
      return;
    }
    if (gesture.mode === 'move') {
      const width = orig.spend1 - orig.spend0;
      const height = orig.eng1 - orig.eng0;
      const spend0 = clamp(
        orig.spend0 + (spend - gesture.spend),
        0,
        SPEND_MAX - width,
      );
      const eng0 = clamp(orig.eng0 + (eng - gesture.eng), 0, ENG_MAX - height);
      dispatch({
        type: 'scatter-brush',
        rect: {spend0, spend1: spend0 + width, eng0, eng1: eng0 + height},
      });
      return;
    }
    // Resize: the grabbed corner follows the pointer; the opposite corner
    // stays anchored, and orderedRect handles crossing over it.
    const anchorSpend =
      gesture.handle === 'nw' || gesture.handle === 'sw'
        ? orig.spend1
        : orig.spend0;
    const anchorEng =
      gesture.handle === 'nw' || gesture.handle === 'ne' ? orig.eng0 : orig.eng1;
    dispatch({
      type: 'scatter-brush',
      rect: orderedRect(anchorSpend, spend, anchorEng, eng),
    });
  };

  const handlePointerEnd = (event: ReactPointerEvent<SVGSVGElement>) => {
    const gesture = gestureRef.current;
    if (gesture == null || gesture.pointerId !== event.pointerId) {
      return;
    }
    gestureRef.current = null;
    if (event.currentTarget.hasPointerCapture(event.pointerId)) {
      event.currentTarget.releasePointerCapture(event.pointerId);
    }
    // A tap on empty plot (no drag) clears the brush; a degenerate sliver
    // from a micro-drag clears too, so stray taps never leave ghost filters.
    if (gesture.mode === 'draw') {
      const current = brush;
      if (
        !gesture.moved ||
        (current != null &&
          current.spend1 - current.spend0 < MIN_BRUSH_SPEND &&
          current.eng1 - current.eng0 < MIN_BRUSH_ENG)
      ) {
        dispatch({type: 'clear-scatter'});
      }
    }
  };

  // Keyboard path — identical dispatches to the pointer gesture: Enter
  // creates a centered brush, arrows nudge, Shift+arrows resize the
  // spend1/eng1 edge, Escape/Delete clears.
  const handleKeyDown = (event: ReactKeyboardEvent<SVGSVGElement>) => {
    const key = event.key;
    if (key === 'Enter' || key === ' ') {
      if (brush == null) {
        dispatch({
          type: 'scatter-brush',
          rect: {
            spend0: SPEND_MAX * 0.25,
            spend1: SPEND_MAX * 0.75,
            eng0: ENG_MAX * 0.25,
            eng1: ENG_MAX * 0.75,
          },
        });
        event.preventDefault();
      }
      return;
    }
    if (key === 'Escape' || key === 'Delete' || key === 'Backspace') {
      if (brush != null) {
        dispatch({type: 'clear-scatter'});
        event.preventDefault();
      }
      return;
    }
    if (brush == null || !key.startsWith('Arrow')) {
      return;
    }
    event.preventDefault();
    if (event.shiftKey) {
      // Resize the far edges, never below the minimum brush size.
      let {spend1, eng1} = brush;
      if (key === 'ArrowRight') {
        spend1 = clamp(spend1 + KEY_STEP_SPEND, brush.spend0, SPEND_MAX);
      } else if (key === 'ArrowLeft') {
        spend1 = clamp(
          spend1 - KEY_STEP_SPEND,
          brush.spend0 + MIN_BRUSH_SPEND,
          SPEND_MAX,
        );
      } else if (key === 'ArrowUp') {
        eng1 = clamp(eng1 + KEY_STEP_ENG, brush.eng0, ENG_MAX);
      } else if (key === 'ArrowDown') {
        eng1 = clamp(eng1 - KEY_STEP_ENG, brush.eng0 + MIN_BRUSH_ENG, ENG_MAX);
      }
      dispatch({type: 'scatter-brush', rect: {...brush, spend1, eng1}});
      return;
    }
    // Nudge: shift the whole rect, clamped so its size is preserved.
    const width = brush.spend1 - brush.spend0;
    const height = brush.eng1 - brush.eng0;
    let spend0 = brush.spend0;
    let eng0 = brush.eng0;
    if (key === 'ArrowRight') {
      spend0 = clamp(spend0 + KEY_STEP_SPEND, 0, SPEND_MAX - width);
    } else if (key === 'ArrowLeft') {
      spend0 = clamp(spend0 - KEY_STEP_SPEND, 0, SPEND_MAX - width);
    } else if (key === 'ArrowUp') {
      eng0 = clamp(eng0 + KEY_STEP_ENG, 0, ENG_MAX - height);
    } else if (key === 'ArrowDown') {
      eng0 = clamp(eng0 - KEY_STEP_ENG, 0, ENG_MAX - height);
    }
    dispatch({
      type: 'scatter-brush',
      rect: {spend0, spend1: spend0 + width, eng0, eng1: eng0 + height},
    });
  };

  const brushLabel =
    brush == null
      ? 'No brush. Press Enter to create one.'
      : `Brush covering ${formatMoney(brush.spend0)} to ${formatMoney(
          brush.spend1,
        )} spend and ${Math.round(brush.eng0)} to ${Math.round(
          brush.eng1,
        )} percent engagement.`;
  const handleVisual = isTouch ? 7 : 4.5;

  return (
    <VStack gap={3}>
      <svg
        ref={svgRef}
        viewBox={`0 0 ${VB_W} ${VB_H}`}
        style={{
          ...styles.scatterSvg,
          outline: isFocused
            ? '2px solid var(--color-accent)'
            : '1px solid transparent',
          outlineOffset: 2,
        }}
        role="application"
        tabIndex={0}
        aria-label={`Spend versus engagement scatter with a rectangle brush. ${brushLabel} Arrow keys move the brush, Shift plus arrows resize it, Escape clears it.`}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerEnd}
        onPointerCancel={handlePointerEnd}
        onKeyDown={handleKeyDown}
        onFocus={() => setIsFocused(true)}
        onBlur={() => setIsFocused(false)}>
        {/* Gridlines + axes (hand-rolled ticks; no chart library). */}
        {SPEND_TICKS.map(tick => (
          <g key={`x-${tick}`}>
            <line
              x1={xOf(tick)}
              x2={xOf(tick)}
              y1={PAD.top}
              y2={PAD.top + PLOT_H}
              stroke={colors.gridline}
              strokeWidth={1}
            />
            <text
              x={xOf(tick)}
              y={VB_H - 12}
              textAnchor="middle"
              fontSize={10}
              fill={colors.tickText}>
              {formatMoney(tick)}
            </text>
          </g>
        ))}
        {ENG_TICKS.map(tick => (
          <g key={`y-${tick}`}>
            <line
              x1={PAD.left}
              x2={PAD.left + PLOT_W}
              y1={yOf(tick)}
              y2={yOf(tick)}
              stroke={colors.gridline}
              strokeWidth={1}
            />
            <text
              x={PAD.left - 8}
              y={yOf(tick) + 3}
              textAnchor="end"
              fontSize={10}
              fill={colors.tickText}>
              {tick}%
            </text>
          </g>
        ))}
        <line
          x1={PAD.left}
          x2={PAD.left + PLOT_W}
          y1={PAD.top + PLOT_H}
          y2={PAD.top + PLOT_H}
          stroke={colors.axis}
          strokeWidth={1}
        />
        <line
          x1={PAD.left}
          x2={PAD.left}
          y1={PAD.top}
          y2={PAD.top + PLOT_H}
          stroke={colors.axis}
          strokeWidth={1}
        />

        {/* Dots: radius maps seats, color maps segment; anything failing any
            linked filter (including this brush) dims to 0.16 opacity. */}
        {ACCOUNTS.map(account => (
          <circle
            key={account.id}
            cx={xOf(account.spend)}
            cy={yOf(account.engagement)}
            r={dotRadius(account.seats)}
            fill={SEGMENT_COLOR[account.segment]}
            opacity={selectedIds.has(account.id) ? 0.85 : 0.16}
            style={
              reducedMotion ? undefined : {transition: 'opacity 140ms ease'}
            }
            pointerEvents="none"
          />
        ))}

        {/* Brush rectangle + corner handles (rendered inert; all hit-testing
            happens in the svg's pointer handlers so capture stays intact). */}
        {brush != null && (
          <g pointerEvents="none">
            <rect
              x={xOf(brush.spend0)}
              y={yOf(brush.eng1)}
              width={xOf(brush.spend1) - xOf(brush.spend0)}
              height={yOf(brush.eng0) - yOf(brush.eng1)}
              fill={colors.brushFill}
              stroke={colors.brushStroke}
              strokeWidth={1.5}
              rx={2}
            />
            {brushHandles(brush).map(handle => (
              <rect
                key={handle.id}
                x={handle.x - handleVisual}
                y={handle.y - handleVisual}
                width={handleVisual * 2}
                height={handleVisual * 2}
                fill={colors.handleFill}
                stroke={colors.brushStroke}
                strokeWidth={1.5}
                rx={2}
              />
            ))}
          </g>
        )}
      </svg>

      {/* Segment legend + interaction hint. */}
      <HStack gap={4} vAlign="center" wrap="wrap">
        {SEGMENTS.map(segment => (
          <HStack key={segment.id} gap={1.5} vAlign="center">
            <span
              style={{...styles.legendSwatch, backgroundColor: segment.color}}
              aria-hidden
            />
            <Text type="supporting" color="secondary" size="sm">
              {segment.label}
            </Text>
          </HStack>
        ))}
        <StackItem size="fill" />
        <Text type="supporting" color="secondary" size="sm">
          Dot size = seats
        </Text>
      </HStack>
    </VStack>
  );
}

// ============= SPEND HISTOGRAM (drag-brushable bins) =============

const BIN_COUNT = 12;
const BIN_WIDTH = SPEND_MAX / BIN_COUNT;

function binRange(bin0: number, bin1: number): SpendRange {
  const lo = Math.min(bin0, bin1);
  const hi = Math.max(bin0, bin1);
  return {min: lo * BIN_WIDTH, max: (hi + 1) * BIN_WIDTH};
}

function binsOfRange(range: SpendRange): [number, number] {
  return [
    clamp(Math.round(range.min / BIN_WIDTH), 0, BIN_COUNT - 1),
    clamp(Math.round(range.max / BIN_WIDTH) - 1, 0, BIN_COUNT - 1),
  ];
}

function histogramCounts(
  accounts: ReadonlyArray<Account>,
  predicate: (account: Account) => boolean,
): number[] {
  const counts = new Array<number>(BIN_COUNT).fill(0);
  for (const account of accounts) {
    if (predicate(account)) {
      const bin = clamp(Math.floor(account.spend / BIN_WIDTH), 0, BIN_COUNT - 1);
      counts[bin] += 1;
    }
  }
  return counts;
}

interface HistogramGesture {
  pointerId: number;
  startBin: number;
  dragged: boolean;
}

function SpendHistogram({
  selection,
  dispatch,
  reducedMotion,
}: {
  selection: Selection;
  dispatch: Dispatch<SelectionAction>;
  reducedMotion: boolean;
}) {
  const wrapRef = useRef<HTMLDivElement | null>(null);
  const gestureRef = useRef<HistogramGesture | null>(null);
  const suppressClickRef = useRef(false);

  // Linking convention: ghost bars are the full book; solid bars are the
  // accounts passing every OTHER facet (scatter brush + segments), so the
  // scatter re-filters this chart live while its own range stays brushable.
  const ghostCounts = useMemo(
    () => histogramCounts(ACCOUNTS, () => true),
    [],
  );
  const activeCounts = useMemo(
    () =>
      histogramCounts(ACCOUNTS, account =>
        accountPasses(account, selection, 'spend'),
      ),
    [selection],
  );
  const maxCount = Math.max(...ghostCounts, 1);
  const rangeBins =
    selection.spend == null ? null : binsOfRange(selection.spend);

  const binAtClientX = (clientX: number): number => {
    const node = wrapRef.current;
    if (node == null) {
      return 0;
    }
    const bounds = node.getBoundingClientRect();
    return clamp(
      Math.floor(((clientX - bounds.left) / bounds.width) * BIN_COUNT),
      0,
      BIN_COUNT - 1,
    );
  };

  const handlePointerDown = (event: ReactPointerEvent<HTMLDivElement>) => {
    if (event.pointerType === 'mouse' && event.button !== 0) {
      return;
    }
    gestureRef.current = {
      pointerId: event.pointerId,
      startBin: binAtClientX(event.clientX),
      dragged: false,
    };
    event.currentTarget.setPointerCapture(event.pointerId);
  };

  const handlePointerMove = (event: ReactPointerEvent<HTMLDivElement>) => {
    const gesture = gestureRef.current;
    if (gesture == null || gesture.pointerId !== event.pointerId) {
      return;
    }
    const bin = binAtClientX(event.clientX);
    if (!gesture.dragged && bin === gesture.startBin) {
      return;
    }
    gesture.dragged = true;
    dispatch({type: 'spend-range', range: binRange(gesture.startBin, bin)});
  };

  const handlePointerEnd = (event: ReactPointerEvent<HTMLDivElement>) => {
    const gesture = gestureRef.current;
    if (gesture == null || gesture.pointerId !== event.pointerId) {
      return;
    }
    gestureRef.current = null;
    if (event.currentTarget.hasPointerCapture(event.pointerId)) {
      event.currentTarget.releasePointerCapture(event.pointerId);
    }
    // A drag already committed on every move; suppress the synthetic click
    // that follows so it can't collapse the range back to one bin.
    suppressClickRef.current = gesture.dragged;
  };

  // Click / keyboard path (bins are real buttons): click sets a single-bin
  // range, Shift+click extends the existing range, clicking the only
  // selected bin clears — all through the same reducer actions as the drag.
  const handleBinActivate = (
    bin: number,
    shiftKey: boolean,
  ) => {
    if (suppressClickRef.current) {
      suppressClickRef.current = false;
      return;
    }
    if (rangeBins != null && shiftKey) {
      dispatch({
        type: 'spend-range',
        range: binRange(Math.min(rangeBins[0], bin), Math.max(rangeBins[1], bin)),
      });
      return;
    }
    if (rangeBins != null && rangeBins[0] === bin && rangeBins[1] === bin) {
      dispatch({type: 'clear-spend'});
      return;
    }
    dispatch({type: 'spend-range', range: binRange(bin, bin)});
  };

  return (
    <VStack gap={2}>
      <div
        ref={wrapRef}
        style={styles.histWrap}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerEnd}
        onPointerCancel={handlePointerEnd}>
        {ghostCounts.map((ghost, bin) => {
          const active = activeCounts[bin];
          const inRange =
            rangeBins != null && bin >= rangeBins[0] && bin <= rangeBins[1];
          const lo = bin * BIN_WIDTH;
          const hi = lo + BIN_WIDTH;
          return (
            <button
              key={bin}
              type="button"
              style={{
                ...styles.histBin,
                ...(inRange ? styles.histBinInRange : undefined),
              }}
              title={`${formatMoney(lo)}–${formatMoney(hi)}: ${active} of ${ghost} accounts`}
              aria-label={`Spend ${formatMoney(lo)} to ${formatMoney(
                hi,
              )}: ${active} brushed of ${ghost} accounts. ${
                inRange ? 'In the selected range.' : ''
              } Enter selects this bin, Shift+Enter extends the range.`}
              aria-pressed={inRange}
              onClick={event => handleBinActivate(bin, event.shiftKey)}>
              <span
                style={{
                  ...styles.histGhostBar,
                  height: `${(ghost / maxCount) * 100}%`,
                }}
                aria-hidden
              />
              <span
                style={{
                  ...styles.histActiveBar,
                  height: `${(active / maxCount) * 100}%`,
                  ...(reducedMotion
                    ? undefined
                    : {transition: 'height 140ms ease'}),
                }}
                aria-hidden
              />
            </button>
          );
        })}
      </div>
      <div style={styles.histAxisRow}>
        <Text type="supporting" color="secondary" size="sm" style={styles.numeric}>
          $0
        </Text>
        <Text type="supporting" color="secondary" size="sm" style={styles.numeric}>
          $5k
        </Text>
        <Text type="supporting" color="secondary" size="sm" style={styles.numeric}>
          $10k
        </Text>
      </div>
      <Text type="supporting" color="secondary" size="sm">
        {selection.spend == null
          ? 'Drag across bins (or click; Shift+click extends) to brush a spend range — the scatter filters in return.'
          : `Spend range ${formatMoney(selection.spend.min)}–${formatMoney(
              selection.spend.max,
            )} is filtering the scatter and table.`}
      </Text>
    </VStack>
  );
}

// ============= SEGMENT BAR CHART (toggle buttons) =============

function SegmentBars({
  selection,
  dispatch,
  reducedMotion,
}: {
  selection: Selection;
  dispatch: Dispatch<SelectionAction>;
  reducedMotion: boolean;
}) {
  // Base counts respect every facet except the segment toggles themselves,
  // so brushing the scatter or histogram reshapes these bars immediately.
  const counts = useMemo(() => {
    const totals: Record<SegmentId, {all: number; brushed: number}> = {
      enterprise: {all: 0, brushed: 0},
      midmarket: {all: 0, brushed: 0},
      smb: {all: 0, brushed: 0},
      startup: {all: 0, brushed: 0},
    };
    for (const account of ACCOUNTS) {
      totals[account.segment].all += 1;
      if (accountPasses(account, selection, 'segments')) {
        totals[account.segment].brushed += 1;
      }
    }
    return totals;
  }, [selection]);
  const maxAll = Math.max(...SEGMENTS.map(s => counts[s.id].all), 1);

  return (
    <VStack gap={1}>
      {SEGMENTS.map(segment => {
        const {all, brushed} = counts[segment.id];
        const isOn = selection.segments.includes(segment.id);
        const isDimmed = selection.segments.length > 0 && !isOn;
        return (
          <button
            key={segment.id}
            type="button"
            style={{
              ...styles.segRow,
              ...(isOn ? styles.segRowActive : undefined),
              opacity: isDimmed ? 0.45 : 1,
              ...(reducedMotion
                ? undefined
                : {transition: 'opacity 140ms ease'}),
            }}
            aria-pressed={isOn}
            aria-label={`${segment.label}: ${brushed} brushed of ${all} accounts. Toggles this segment as a filter.`}
            onClick={() =>
              dispatch({type: 'toggle-segment', segment: segment.id})
            }>
            <span style={styles.segLabelCol}>
              <Text type="supporting" maxLines={1}>
                {segment.label}
              </Text>
            </span>
            <span style={styles.segTrack}>
              <span
                style={{
                  ...styles.segGhostBar,
                  width: `${(all / maxAll) * 100}%`,
                }}
                aria-hidden
              />
              <span
                style={{
                  ...styles.segActiveBar,
                  width: `${(brushed / maxAll) * 100}%`,
                  backgroundColor: segment.color,
                  ...(reducedMotion
                    ? undefined
                    : {transition: 'width 140ms ease'}),
                }}
                aria-hidden
              />
            </span>
            <span style={styles.segCountCol}>
              <Text type="supporting" color="secondary" style={styles.numeric}>
                {brushed}/{all}
              </Text>
            </span>
          </button>
        );
      })}
      <Text type="supporting" color="secondary" size="sm">
        Tap a segment to keep only it; tap again to release. Bars re-count
        under the current brushes.
      </Text>
    </VStack>
  );
}

// ============= FILTER CHIPS =============

function FilterChips({
  selection,
  dispatch,
}: {
  selection: Selection;
  dispatch: Dispatch<SelectionAction>;
}) {
  const chips: Array<{id: string; label: string; onRemove: () => void}> = [];
  if (selection.scatter != null) {
    const b = selection.scatter;
    chips.push({
      id: 'scatter',
      label: `Scatter · ${formatMoney(b.spend0)}–${formatMoney(
        b.spend1,
      )} · ${Math.round(b.eng0)}–${Math.round(b.eng1)}% eng`,
      onRemove: () => dispatch({type: 'clear-scatter'}),
    });
  }
  if (selection.spend != null) {
    chips.push({
      id: 'spend',
      label: `Spend ${formatMoney(selection.spend.min)}–${formatMoney(
        selection.spend.max,
      )}`,
      onRemove: () => dispatch({type: 'clear-spend'}),
    });
  }
  for (const segment of selection.segments) {
    chips.push({
      id: `segment-${segment}`,
      label: `Segment · ${SEGMENT_LABEL[segment]}`,
      onRemove: () => dispatch({type: 'toggle-segment', segment}),
    });
  }

  return (
    <HStack gap={2} vAlign="center" wrap="wrap" style={styles.chipRow}>
      {chips.length === 0 ? (
        <Text type="supporting" color="secondary">
          No active brushes — drag on any chart to start filtering.
        </Text>
      ) : (
        <>
          {chips.map(chip => (
            <Token
              key={chip.id}
              label={chip.label}
              size="sm"
              onRemove={chip.onRemove}
            />
          ))}
          <Button
            label="Clear all"
            variant="ghost"
            size="sm"
            onClick={() => dispatch({type: 'clear-all'})}
          />
        </>
      )}
    </HStack>
  );
}

