// ============= PAGE =============

const TABLE_LIMIT = 10;

export default function MetricBrushExplorerTemplate() {
  const [selection, dispatch] = useReducer(selectionReducer, EMPTY_SELECTION);

  // Responsive contract: <=640px swaps the chart grid for a scroll-snap
  // carousel; (hover: none) grows the brush corner hit zones to ~44px.
  const isCompact = useMediaQuery('(max-width: 640px)');
  const isTouch = useMediaQuery('(hover: none)');
  const reducedMotion = useMediaQuery('(prefers-reduced-motion: reduce)');

  // The brushed set: accounts passing every linked facet. Because the drag
  // handlers dispatch on every pointer move, this — and the stats strip,
  // histogram, bars, and table below — recomputes live mid-gesture.
  const brushedIds = useMemo(() => {
    const ids = new Set<string>();
    for (const account of ACCOUNTS) {
      if (accountPasses(account, selection)) {
        ids.add(account.id);
      }
    }
    return ids;
  }, [selection]);

  const brushedAccounts = useMemo(
    () => ACCOUNTS.filter(account => brushedIds.has(account.id)),
    [brushedIds],
  );

  const stats = useMemo(() => {
    const spends = brushedAccounts.map(account => account.spend);
    const seats = brushedAccounts.reduce((sum, a) => sum + a.seats, 0);
    return {
      count: brushedAccounts.length,
      medianSpend: median(spends),
      seats,
      seatShare: Math.round((seats / TOTAL_SEATS) * 100),
    };
  }, [brushedAccounts]);

  const tableRows = useMemo<AccountRow[]>(
    () =>
      [...brushedAccounts]
        .sort((a, b) => b.spend - a.spend)
        .slice(0, TABLE_LIMIT)
        .map(account => ({...account})),
    [brushedAccounts],
  );

  const hasSelection =
    selection.scatter != null ||
    selection.spend != null ||
    selection.segments.length > 0;

  const activePresetId =
    PRESET_BRUSHES.find(preset => {
      const b = selection.scatter;
      return (
        b != null &&
        b.spend0 === preset.rect.spend0 &&
        b.spend1 === preset.rect.spend1 &&
        b.eng0 === preset.rect.eng0 &&
        b.eng1 === preset.rect.eng1
      );
    })?.id ?? null;

  const scatterCard = (
    <Card>
      <VStack gap={3}>
        <HStack gap={2} vAlign="center" wrap="wrap">
          <StackItem size="fill">
            <VStack gap={0}>
              <Heading level={3}>Spend vs engagement</Heading>
              <Text type="supporting" color="secondary">
                Drag a rectangle to brush; drag its body to move it, corners
                to resize. Keyboard: Enter, arrows, Shift+arrows, Escape.
              </Text>
            </VStack>
          </StackItem>
        </HStack>
        <ScatterBrushChart
          selection={selection}
          selectedIds={brushedIds}
          dispatch={dispatch}
          isTouch={isTouch}
          reducedMotion={reducedMotion}
        />
        {/* Preset brushes: the button path into the exact same reducer
            commit the drag gesture uses. */}
        <HStack gap={2} vAlign="center" wrap="wrap">
          <Text type="supporting" color="secondary" size="sm">
            Presets:
          </Text>
          {PRESET_BRUSHES.map(preset => (
            <Button
              key={preset.id}
              label={preset.label}
              size="sm"
              variant={activePresetId === preset.id ? 'secondary' : 'ghost'}
              onClick={() =>
                dispatch({type: 'scatter-brush', rect: preset.rect})
              }
            />
          ))}
        </HStack>
      </VStack>
    </Card>
  );

  const histogramCard = (
    <Card>
      <VStack gap={3}>
        <VStack gap={0}>
          <Heading level={3}>Spend distribution</Heading>
          <Text type="supporting" color="secondary">
            Solid bars = accounts passing the other brushes.
          </Text>
        </VStack>
        <SpendHistogram
          selection={selection}
          dispatch={dispatch}
          reducedMotion={reducedMotion}
        />
      </VStack>
    </Card>
  );

  const segmentCard = (
    <Card>
      <VStack gap={3}>
        <VStack gap={0}>
          <Heading level={3}>Segments</Heading>
          <Text type="supporting" color="secondary">
            Brushed count vs full book per segment.
          </Text>
        </VStack>
        <SegmentBars
          selection={selection}
          dispatch={dispatch}
          reducedMotion={reducedMotion}
        />
      </VStack>
    </Card>
  );

  return (
    <Layout
      height="fill"
      header={
        <LayoutHeader hasDivider>
          <HStack gap={3} vAlign="center" wrap="wrap">
            <StackItem size="fill">
              <HStack gap={2} vAlign="center">
                <Heading level={1}>Metric Brush Lab</Heading>
                <Text type="supporting" color="secondary" style={styles.numeric}>
                  {stats.count} of {ACCOUNTS.length} accounts brushed
                </Text>
              </HStack>
            </StackItem>
            {hasSelection && (
              <Button
                label="Clear all brushes"
                variant="secondary"
                size="sm"
                onClick={() => dispatch({type: 'clear-all'})}
              />
            )}
          </HStack>
        </LayoutHeader>
      }
      content={
        <LayoutContent padding={6} label="Linked metric explorer">
          <div style={styles.page}>
            <VStack gap={5}>
              {/* Active selections as removable chips. */}
              <FilterChips selection={selection} dispatch={dispatch} />

              {/* Lasso-stats strip — recomputed on every pointer move
                  because the gesture dispatches per-move. */}
              <Grid columns={{minWidth: 180, max: 3}} gap={4}>
                <Card>
                  <Stat
                    label="Accounts in brush"
                    value={formatCount(stats.count)}
                    description={`of ${ACCOUNTS.length} total`}
                  />
                </Card>
                <Card>
                  <Stat
                    label="Median spend"
                    value={
                      stats.count > 0 ? formatMoney(stats.medianSpend) : '—'
                    }
                    description="per month, brushed set"
                  />
                </Card>
                <Card>
                  <Stat
                    label="Total seats"
                    value={stats.count > 0 ? formatCount(stats.seats) : '—'}
                    description={
                      stats.count > 0
                        ? `${stats.seatShare}% of all seats`
                        : 'brush to compute'
                    }
                  />
                </Card>
              </Grid>

              {/* Linked charts: desktop 2-col grid (scatter spans left),
                  <=640px a scroll-snap carousel with a swipe hint. */}
              {isCompact ? (
                <VStack gap={2}>
                  <div style={styles.chartSnapRow}>
                    <div style={styles.chartSnapSlide}>{scatterCard}</div>
                    <div style={styles.chartSnapSlide}>{histogramCard}</div>
                    <div style={styles.chartSnapSlide}>{segmentCard}</div>
                  </div>
                  <Text type="supporting" color="secondary" size="sm">
                    Swipe sideways for the histogram and segment charts — all
                    three stay linked to the same brush.
                  </Text>
                </VStack>
              ) : (
                <div style={styles.chartGrid}>
                  <div style={styles.scatterCell}>{scatterCard}</div>
                  <div style={styles.sideCell}>{histogramCard}</div>
                  <div style={styles.sideCell}>{segmentCard}</div>
                </div>
              )}

              {/* Brushed accounts table — same shared selection. */}
              <Card>
                <VStack gap={4}>
                  <HStack gap={2} vAlign="center" wrap="wrap">
                    <StackItem size="fill">
                      <Heading level={3}>Brushed accounts</Heading>
                    </StackItem>
                    <Text
                      type="supporting"
                      color="secondary"
                      style={styles.numeric}>
                      {stats.count === 0
                        ? 'No accounts match'
                        : stats.count <= TABLE_LIMIT
                          ? `${stats.count} accounts`
                          : `Top ${TABLE_LIMIT} of ${stats.count} by spend`}
                    </Text>
                  </HStack>
                  {tableRows.length > 0 ? (
                    <div style={styles.tableScroll}>
                      <Table<AccountRow>
                        data={tableRows}
                        columns={accountColumns}
                        idKey="id"
                        density="compact"
                        dividers="rows"
                        hasHover
                      />
                    </div>
                  ) : (
                    <div style={styles.emptyBody}>
                      <EmptyState
                        isCompact
                        icon={
                          <Icon
                            icon={hasSelection ? BoxSelectIcon : InboxIcon}
                            size="lg"
                          />
                        }
                        title="Nothing in the brush"
                        description="The current brushes exclude every account. Widen the rectangle or remove a chip above."
                        actions={
                          hasSelection ? (
                            <Button
                              label="Clear all brushes"
                              size="sm"
                              onClick={() => dispatch({type: 'clear-all'})}
                            />
                          ) : undefined
                        }
                      />
                    </div>
                  )}
                </VStack>
              </Card>
            </VStack>
          </div>
        </LayoutContent>
      }
    />
  );
}
